/* --- UTF-8 decoding --- */

/*
 * Returns:
 *   1  = complete codepoint in *out
 *   0  = incomplete, need more bytes
 *  -1  = replacement char (U+FFFD) in *out, caller must re-feed this byte
 */
static int utf8_decode_byte(Utf8Decoder *dec, uint8_t byte, uint32_t *out) {
    if (dec->remaining > 0) {
        if ((byte & 0xC0) != 0x80) {
            /* Invalid continuation — emit U+FFFD for the broken sequence,
             * signal caller to re-feed this byte as a new sequence start */
            dec->remaining = 0;
            *out = 0xFFFD;
            return -1;
        }
        dec->codepoint = (dec->codepoint << 6) | (byte & 0x3F);
        dec->remaining--;
        if (dec->remaining == 0) {
            uint32_t cp = dec->codepoint;
            /* Reject overlong encodings and surrogates */
            if ((dec->expected == 2 && cp < 0x80) ||
                (dec->expected == 3 && cp < 0x800) ||
                (dec->expected == 4 && cp < 0x10000) ||
                (cp >= 0xD800 && cp <= 0xDFFF) ||
                cp > 0x10FFFF) {
                *out = 0xFFFD;
            } else {
                *out = cp;
            }
            return 1;
        }
        return 0;
    }

    if (byte < 0x80) {
        *out = byte;
        return 1;
    } else if ((byte & 0xE0) == 0xC0) {
        dec->codepoint = byte & 0x1F;
        dec->remaining = 1;
        dec->expected = 2;
    } else if ((byte & 0xF0) == 0xE0) {
        dec->codepoint = byte & 0x0F;
        dec->remaining = 2;
        dec->expected = 3;
    } else if ((byte & 0xF8) == 0xF0) {
        dec->codepoint = byte & 0x07;
        dec->remaining = 3;
        dec->expected = 4;
    } else {
        /* Invalid start byte (0x80-0xBF, 0xFE, 0xFF) — emit replacement */
        *out = 0xFFFD;
        return 1;
    }
    return 0;
}

