/* --- Tcl interpreter access from Python's Tkinter ---
 * Python's _tkinter module stores the Tcl_Interp as an integer address.
 * We get it via: root.tk.interpaddr() → integer → (Tcl_Interp *) */

/* Probe: draw a single rectangle on a canvas to test Tcl_Eval from C */
static PyObject *phc_tk_probe(PyObject *self, PyObject *args) {
    (void)self;
    unsigned long long interp_addr;
    const char *canvas_path;

    if (!PyArg_ParseTuple(args, "Ks", &interp_addr, &canvas_path))
        return NULL;

    Tcl_Interp *interp = (Tcl_Interp *)(uintptr_t)interp_addr;

    /* Try a simple canvas command */
    char cmd[256];
    snprintf(cmd, sizeof(cmd),
        "%s create rectangle 10 10 50 50 -fill red -outline \"\"",
        canvas_path);

    int result = Tcl_Eval(interp, cmd);
    if (result != TCL_OK) {
        PyErr_Format(PyExc_RuntimeError,
            "Tcl_Eval failed: %s", Tcl_GetStringResult(interp));
        return NULL;
    }

    /* Return the canvas item ID */
    const char *res = Tcl_GetStringResult(interp);
    return PyUnicode_FromString(res);
}

/* Headless Tcl ABI smoke test: creates an interpreter, runs 'expr 1+1'
 * via Tcl_EvalObjv, returns the result string. Catches version mismatches
 * and linkage errors without needing a display. */
static PyObject *phc_tcl_smoke_test(PyObject *self, PyObject *args) {
    (void)self;
    (void)args;

    Tcl_Interp *interp = Tcl_CreateInterp();
    if (!interp) {
        PyErr_SetString(PyExc_RuntimeError, "Failed to create Tcl interpreter");
        return NULL;
    }

    /* Run 'expr 1+1' via Tcl_EvalObjv */
    Tcl_Obj *objv[2];
    objv[0] = Tcl_NewStringObj("expr", -1);
    objv[1] = Tcl_NewStringObj("1+1", -1);
    Tcl_IncrRefCount(objv[0]);
    Tcl_IncrRefCount(objv[1]);

    int rc = Tcl_EvalObjv(interp, 2, objv, 0);

    Tcl_DecrRefCount(objv[0]);
    Tcl_DecrRefCount(objv[1]);

    if (rc != TCL_OK) {
        const char *err = Tcl_GetStringResult(interp);
        PyErr_Format(PyExc_RuntimeError, "Tcl_EvalObjv failed: %s", err);
        Tcl_DeleteInterp(interp);
        return NULL;
    }

    const char *result = Tcl_GetStringResult(interp);
    PyObject *py_result = PyUnicode_FromString(result);

    Tcl_DeleteInterp(interp);
    return py_result;
}

