/* --- Module definition --- */

static PyModuleDef nbsterm_module = {
    PyModuleDef_HEAD_INIT,
    "_nbsterm",
    "NBS Terminal Emulator C Extension",
    -1,
    module_methods, NULL, NULL, NULL, NULL
};

PyMODINIT_FUNC PyInit__nbsterm(void) {
    PyObject *m = PyModule_Create(&nbsterm_module);
    if (!m) return NULL;

    if (PyType_Ready(&TerminalType) < 0) return NULL;
    Py_INCREF(&TerminalType);
    if (PyModule_AddObject(m, "Terminal", (PyObject *)&TerminalType) < 0) {
        Py_DECREF(&TerminalType);
        Py_DECREF(m);
        return NULL;
    }

    if (add_key_constants(m) < 0) {
        Py_DECREF(m);
        return NULL;
    }

    return m;
}
